 15→//! Utility for commit evolution history.
 16→
 17→use std::collections::BTreeMap;
 18→use std::collections::HashMap;
 19→use std::collections::VecDeque;
 20→use std::collections::hash_map::Entry;
 21→use std::slice;
 22→
 23→use itertools::Itertools as _;
 24→use thiserror::Error;
